import akka.actor.{Actor, ActorSystem}
import scala.concurrent._
import scala.util.Random
object Account {
  def main(args: Array[String]): Unit = {
    val system = ActorSystem("Account")

    val account = new AccountActor()
    system.actorOf(Props(account), "account")

    for (i <- 1 to 50) {
      system.actorSelection("/user/account").tell(Random.nextInt, ActorRef())
    }
  }
}
class AccountActor extends Actor {
  var balance = 0

  override def receive: Receive = {
    case n =>
      val newBalance = balance + n

      if (newBalance < 0) {
        println("Insufficient funds")
      } else {
        balance = newBalance

        println(s"New balance is $balance")
      }
  }
}

